// Country id → short display name (source special-cases UAE).
export function shortName(name: string): string {
  return name === "United Arab Emirates" ? "UAE" : name;
}

// Lookup by numeric country id.
export const CMAP: Record<string, Country> = Object.fromEntries(
  COUNTRIES.map((c) => [c.id, c]),
);

// Centroid used for the timeline pulse ring (source centroidOf).
export function centroidOf(c: Country): [number, number] {
  if (c.hub) return c.hub;
  if (c.label.leader) return c.label.leader;
  return [c.label.x, c.label.y - 3];
}
